package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link MergingWindowAssigner} that assigns elements to session windows based on market
 * trading hours.
 *
 * <p>This assigner creates time windows aligned with specific market trading sessions. Each
 * market has defined opening and closing times in a specified timezone. Elements are assigned
 * to the session window that contains their event timestamp.
 *
 * <p>Windows that overlap in time will be merged, allowing for dynamic session-based event
 * grouping in capital markets streaming analytics.
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    /**
     * Creates a new PricingSessionWindow for the specified market and trading hours.
     *
     * @param marketId The identifier for the market (e.g., "NYSE", "LSE").
     * @param timezone The timezone in which trading hours are defined.
     * @param sessionOpen The opening time of the trading session (inclusive).
     * @param sessionClose The closing time of the trading session (exclusive).
     */
    public PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        TimeWindow window = getSessionWindow(timestamp);
        return Collections.singleton(window);
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger(
            Trigger.TriggerContext context) {
        return EventTimeTrigger.create();
    }

    @Override
    public String getUniqueIdentifier() {
        return "PricingSessionWindow(" + marketId + "," + timezone + ")";
    }

    @Override
    public void mergeWindows(Collection<TimeWindow> windows, MergeCallback<TimeWindow> callback) {
        TimeWindow.mergeWindows(windows, callback);
    }

    /**
     * Creates a PricingSessionWindow for the specified market.
     *
     * @param marketId The identifier for the market.
     * @param timezone The timezone in which trading hours are defined.
     * @param sessionOpen The opening time of the trading session.
     * @param sessionClose The closing time of the trading session.
     * @return A new PricingSessionWindow instance.
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
    }

    /**
     * Gets the market ID for this window assigner.
     *
     * @return The market ID.
     */
    public String getMarketId() {
        return marketId;
    }

    /**
     * Gets the timezone for this window assigner.
     *
     * @return The timezone.
     */
    public ZoneId getTimezone() {
        return timezone;
    }

    /**
     * Gets the session open time for this window assigner.
     *
     * @return The session open time.
     */
    public LocalTime getSessionOpen() {
        return sessionOpen;
    }

    /**
     * Gets the session close time for this window assigner.
     *
     * @return The session close time.
     */
    public LocalTime getSessionClose() {
        return sessionClose;
    }

    private TimeWindow getSessionWindow(long timestamp) {
        ZonedDateTime eventTime = ZonedDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(timestamp), timezone);
        ZonedDateTime sessionStartDateTime = eventTime.with(sessionOpen);

        if (eventTime.isBefore(sessionStartDateTime)) {
            sessionStartDateTime = sessionStartDateTime.minusDays(1);
        }

        ZonedDateTime sessionEndDateTime = sessionStartDateTime.with(sessionClose);

        if (eventTime.isAfter(sessionEndDateTime) || eventTime.equals(sessionEndDateTime)) {
            sessionStartDateTime = sessionStartDateTime.plusDays(1);
            sessionEndDateTime = sessionStartDateTime.with(sessionClose);
        }

        long windowStart = sessionStartDateTime.toInstant().toEpochMilli();
        long windowEnd = sessionEndDateTime.toInstant().toEpochMilli();

        return new TimeWindow(windowStart, windowEnd);
    }
