import org.apache.flink.api.common.state.ReducingStateDescriptor;
import org.apache.flink.api.common.typeutils.base.LongSerializer;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A trigger for pricing session windows that fires when the end time of the window
 * is reached based on event time. This trigger is designed to work with market session
 * windows where events are grouped by trading session identifiers.
 */
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {

	private static final long serialVersionUID = 1L;

	private final ReducingStateDescriptor<Long> stateDescriptor =
			new ReducingStateDescriptor<>(
					"pricing-session-trigger-state",
					new ReduceFunction<Long>() {
						@Override
						public Long reduce(Long value1, Long value2) {
							return Math.max(value1, value2);
						}
					},
					LongSerializer.INSTANCE);

	@Override
	public TriggerResult onElement(Object element, long timestamp, TimeWindow window, TriggerContext ctx)
			throws Exception {
		ReducingState<Long> firingTime = ctx.getPartitionedState(stateDescriptor);

		Long lastFiringTime = firingTime.get();
		if (lastFiringTime == null) {
			lastFiringTime = window.getEnd();
		}

		if (timestamp >= window.getEnd()) {
			firingTime.add(window.getEnd());
			ctx.registerEventTimeCallback(window.getEnd(), ctx);
			return TriggerResult.FIRE;
		}

		ctx.registerEventTimeCallback(window.getEnd(), ctx);
		return TriggerResult.CONTINUE;
	}

	@Override
	public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
			throws Exception {
		return TriggerResult.CONTINUE;
	}

	@Override
	public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx)
			throws Exception {
		if (time == window.getEnd()) {
			return TriggerResult.FIRE;
		}
		return TriggerResult.CONTINUE;
	}

	@Override
	public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
		ctx.getPartitionedState(stateDescriptor).clear();
	}

	@Override
	public boolean canMerge() {
		return true;
	}

	@Override
	public TriggerResult onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
		ctx.mergePartitionedState(stateDescriptor);
		return TriggerResult.CONTINUE;
	}

	@Override
	public String toString() {
		return "PricingSessionTrigger()";
	}
